{"file_text": "@if (TotalPages > 1)
{
    <nav aria-label="Product catalog pagination">
        <ul class="pagination justify-content-center mt-4">
            <li class="page-item @(Page <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(Page - 1))" disabled="@(Page <= 1)">
                    Previous
                </button>
            </li>

            @foreach (var p in PageNumbers)
            {
                <li class="page-item @(p == Page ? "active" : "")">
                    <button class="page-link" @onclick="@(() => GoToPage(p))">@p</button>
                </li>
            }

            <li class="page-item @(Page >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(Page + 1))" disabled="@(Page >= TotalPages)">
                    Next
                </button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter] public int Page { get; set; }
    [Parameter] public int TotalCount { get; set; }
    [Parameter] public int PageSize { get; set; }
    [Parameter] public EventCallback<int> OnPageChanged { get; set; }

    private int TotalPages => PageSize > 0 ? (int)Math.Ceiling((double)TotalCount / PageSize) : 1;

    private IEnumerable<int> PageNumbers
    {
        get
        {
            int start = Math.Max(1, Page - 2);
            int end = Math.Min(TotalPages, start + 4);
            start = Math.Max(1, end - 4);
            return Enumerable.Range(start, end - start + 1);
        }
    }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != Page)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}
