@* A single product card showing image placeholder, name, price, rating, stock badge, and Add to Cart *@

<div class="product-card" @onclick="HandleCardClick">
    <div class="product-image-placeholder" role="img" aria-label="@Product.Name">
        @Product.Name
    </div>

    <div class="product-card-body">
        <h5 class="product-name" title="@Product.Name">@Product.Name</h5>
        <p class="product-price">@Product.Price.ToString("C")</p>
        <div class="product-rating" aria-label="@($"{Product.Rating:F1} out of 5 stars")">
            @RatingStars
        </div>

        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }

        <button class="btn btn-primary btn-sm w-100"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private string RatingStars
    {
        get
        {
            int filled = (int)Math.Round(Product.Rating);
            return new string('★', filled) + new string('☆', 5 - filled);
        }
    }

    private async Task HandleCardClick()
    {
        await OnProductSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }
}

