@page "/catalog"
@using sv_b0c3cebe266442828cfeb736258bc7fd.Components.Pages.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

@if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="RetryLoad">Retry</button>
    </div>
}
else if (isLoading)
{
    <div class="d-flex justify-content-center align-items-center py-5">
        <div class="spinner-border text-primary me-3" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
        <span>Loading products…</span>
    </div>
}
else
{
    <div class="catalog-layout">
        <aside class="catalog-sidebar">
            <CatalogFilters Categories="categories" OnFiltersApplied="HandleFiltersApplied" />
        </aside>

        <section class="catalog-main">
            <CatalogToolbar SortBy="@sortBy"
                            Page="currentPage"
                            PageSize="PageSize"
                            TotalCount="totalCount"
                            OnSortChanged="HandleSortChanged" />

            @if (products.Count == 0)
            {
                <div class="alert alert-info text-center" role="status">
                    No products found matching your filters. Try adjusting your criteria.
                </div>
            }
            else
            {
                <ProductGrid Products="products"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />
            }

            <CatalogPagination Page="currentPage"
                               TotalCount="totalCount"
                               PageSize="PageSize"
                               OnPageChanged="HandlePageChanged" />
        </section>
    </div>
}

@code {
    private const int PageSize = 12;

    private List<Product> products = [];
    private List<string> categories = [];
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private int totalCount;
    private bool isLoading = true;
    private string? errorMessage;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            categories = await categoriesTask;
            var result = await searchTask;
            products = result.Items;
            totalCount = result.TotalCount;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);
            products = result.Items;
            totalCount = result.TotalCount;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleFiltersApplied(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
        return Task.CompletedTask;
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }
}

.catalog-layout {
    display: flex;
    gap: 1.5rem;
}

.catalog-sidebar {
    flex: 0 0 25%;
    min-width: 220px;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

@media (max-width: 768px) {
    .catalog-layout {
        flex-direction: column;
    }

    .catalog-sidebar {
        flex: none;
    }
}

